package com.ayush.springtest; import org.junit.jupiter.api.Test; import java.util.*; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*; class UserServiceTest { @Test void mockRepositoryInService(){ UserRepository repo=mock(UserRepository.class); when(repo.findById(1L)).thenReturn(Optional.of(new User(1L,"Ayush"))); assertEquals("Ayush", new UserService(repo).getUserById(1L).getName()); } @Test void serviceExceptionHandling(){ UserRepository repo=mock(UserRepository.class); when(repo.findById(99L)).thenReturn(Optional.empty()); assertThrows(NoSuchElementException.class, () -> new UserService(repo).getUserById(99L)); }}